import { useState } from 'react';
import { useMoodStore, type Mood } from '../store/moodStore';
import { motion, AnimatePresence } from 'framer-motion';

const moods: { id: Mood; label: string; description: string }[] = [
  { id: 'luxurious', label: 'Luxurious', description: 'Exclusive dining, high-end experiences' },
  { id: 'tranquil', label: 'Tranquil', description: 'Spa, quiet lounges, relaxation' },
  { id: 'energetic', label: 'Energetic', description: 'Nightlife, parties, vibrant scenes' },
  { id: 'adventurous', label: 'Adventurous', description: 'Yacht trips, helicopter tours' },
  { id: 'romantic', label: 'Romantic', description: 'Intimate dinners, sunset views' },
  { id: 'focused', label: 'Focused', description: 'Private workspaces, discreet meetings' }
];

export function MoodOnboarding() {
  const { currentMood, setMood, addDesire, desireMemory } = useMoodStore();
  const [customDesire, setCustomDesire] = useState('');

  const handleSelectMood = (mood: Mood) => {
    setMood(mood);
  };

  const handleAddDesire = () => {
    if (customDesire.trim()) {
      addDesire(customDesire.trim());
      setCustomDesire('');
    }
  };

  return (
    <div className="min-h-screen bg-nocturnal-900 text-white flex flex-col items-center justify-center p-6 relative overflow-hidden">
      {/* Background Ambience */}
      <div className="absolute top-0 left-0 w-full h-full pointer-events-none">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-gold/5 blur-[120px] rounded-full" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-gold/10 blur-[150px] rounded-full" />
      </div>

      <motion.div 
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8 }}
        className="glass-card max-w-2xl w-full p-8 md:p-12 relative z-10 border border-white/5"
      >
        <div className="text-center mb-10">
          <h1 className="text-4xl md:text-5xl font-light tracking-tight mb-4 text-gold drop-shadow-[0_0_10px_rgba(212,175,55,0.2)]">
            Define Your Vibe
          </h1>
          <p className="text-gray-400 text-sm md:text-base tracking-wide">
            The ecosystem adapts to your current state of mind.
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
          {moods.map((m) => (
            <motion.button
              key={m.id}
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
              onClick={() => handleSelectMood(m.id)}
              className={`p-4 rounded-elite text-left transition-all border ${
                currentMood === m.id
                  ? 'bg-gold/10 border-gold/50 shadow-[0_0_20px_rgba(212,175,55,0.15)]'
                  : 'bg-white/5 border-white/10 hover:bg-white/10'
              }`}
            >
              <h3 className={`text-lg mb-1 ${currentMood === m.id ? 'text-gold' : 'text-white'}`}>
                {m.label}
              </h3>
              <p className="text-xs text-gray-500">{m.description}</p>
            </motion.button>
          ))}
        </div>

        <AnimatePresence>
          {currentMood !== 'unset' && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: 'auto' }}
              exit={{ opacity: 0, height: 0 }}
              className="mt-8 border-t border-white/10 pt-8"
            >
              <h4 className="text-lg text-gold mb-3">Specific Desire</h4>
              <div className="flex gap-3">
                <input
                  type="text"
                  value={customDesire}
                  onChange={(e) => setCustomDesire(e.target.value)}
                  placeholder="e.g. 'A quiet table by the window', 'Oysters'"
                  className="flex-1 bg-black/50 border border-white/10 rounded-full px-6 py-3 text-sm focus:outline-none focus:border-gold/50 text-white placeholder-gray-600 transition-colors"
                />
                <button 
                  onClick={handleAddDesire}
                  className="btn-gold !py-3 !px-6"
                >
                  Save
                </button>
              </div>

              {desireMemory.length > 0 && (
                <div className="mt-6 flex flex-wrap gap-2">
                  {desireMemory.map((desire, idx) => (
                    <span 
                      key={idx}
                      className="text-xs px-3 py-1.5 bg-black/60 border border-gold/20 rounded-full text-gold-light"
                    >
                      {desire}
                    </span>
                  ))}
                </div>
              )}
            </motion.div>
          )}
        </AnimatePresence>
      </motion.div>
    </div>
  );
}
